require_once dirname(__DIR__).'/includes/cms.php';exigirPermiso('audit.view');$id=cmsId($_GET['id']??0);$q=obtenerConexion()->prepare('SELECT a.*,CONCAT(actor.nombre," ",actor.apellido) actor_nombre,CONCAT(target.nombre," ",target.apellido) target_nombre FROM audit_logs a LEFT JOIN usuarios actor ON actor.id=a.actor_user_id LEFT JOIN usuarios target ON target.id=a.target_user_id WHERE a.id=:id');$q->execute(['id'=>$id]);$evento=$q->fetch();if(!$evento){cmsFlash('error','El evento no existe.');header('Location:index.php');exit;}$metadata=json_decode((string)($evento['metadata']??''),true);cmsCabecera('Detalle de bitacora','bitacora/detalle.php','Registro de solo lectura.');?><div class="card card-rounded"><div class="card-body"><dl class="row"><dt class="col-md-3">Fecha</dt><dd class="col-md-9"><?= atenea_e((string)$evento['created_at']) ?></dd><dt class="col-md-3">Evento</dt><dd class="col-md-9"><?= atenea_e((string)$evento['event_type']) ?></dd><dt class="col-md-3">Actor</dt><dd class="col-md-9"><?= atenea_e((string)($evento['actor_nombre']?:'Sistema')) ?></dd><dt class="col-md-3">Objetivo</dt><dd class="col-md-9"><?= atenea_e((string)($evento['target_nombre']?:'-')) ?></dd><dt class="col-md-3">Accion / resultado</dt><dd class="col-md-9"><?= atenea_e((string)$evento['action'].' / '.(string)$evento['result']) ?></dd><dt class="col-md-3">Descripcion</dt><dd class="col-md-9"><?= atenea_e((string)$evento['description']) ?></dd><dt class="col-md-3">IP</dt><dd class="col-md-9"><?= atenea_e((string)($evento['ip_address']?:'No disponible')) ?></dd><dt class="col-md-3">Agente resumido</dt><dd class="col-md-9"><?= atenea_e((string)$evento['user_agent']) ?></dd><dt class="col-md-3">Request ID</dt><dd class="col-md-9"><code><?= atenea_e((string)$evento['request_id']) ?></code></dd><dt class="col-md-3">Metadata sanitizada</dt><dd class="col-md-9"><pre class="bg-light p-3 rounded mb-0"><?= atenea_e($metadata?json_encode($metadata,JSON_PRETTY_PRINT|JSON_UNESCAPED_UNICODE):'Sin metadata') ?></pre></dd></dl><a class="btn btn-light" href="index.php">Volver</a></div></div><?php cmsPie(); ?>
